function e(e,t){if(!e)return``;if(t){let n=t(e);if(n?.display_name)return n.display_name;if(n?.username)return`@${n.username}`}if(e===`system`)return`System`;if(e.startsWith(`group:`)){let t=e.split(`:`);if(t.length>=3)return`${t[1].charAt(0).toUpperCase()+t[1].slice(1)} ${t.slice(2).join(`:`)}`}return/^-?\d+$/.test(e)?`#${e}`:e.length>20?`${e.slice(0,10)}…${e.slice(-4)}`:e}export{e as t};